mapper.select:
SELECT GROUP_CONCAT(IF(h.out_temperature > 0, h.out_temperature, NULL) ORDER BY h.create_time) AS 'nowTemperatureString', GROUP_CONCAT(IF(h.out_temperature > 0, h.valve_status, NULL) ORDER BY h.create_time) AS 'nowValveStatusString', GROUP_CONCAT(IF(h.out_temperature > 0, DATE_FORMAT(h.create_time, '%Y-%m-%d %H:%i:00'), NULL) ORDER BY h.create_time) AS 'nowTimeString', h.meter_num, h.out_temperature, h.valve_status, h.create_time, h.read_time, d.room_num AS 'roomNum' FROM pr_heat_reading h LEFT JOIN pr_heat_valve_archive b ON h.meter_num = b.meter_num LEFT JOIN pr_house d ON b.house_id = d.id AND b.company_id = d.company_id AND b.org_id = d.org_id LEFT JOIN sys_organization F ON b.ORG_ID = F.ID WHERE b.company_id = #{companyId}
AND h.meter_num IN
#{item}
AND h.create_time BETWEEN #{startTime} AND #{endTime}
AND b.org_id = #{orgId}
AND F.parent_id = #{parentId}
AND h.out_temperature != 0 GROUP BY b.meter_num ORDER BY h.create_time

SELECT GROUP_CONCAT(IF(aa.out_temperature > 0, aa.out_temperature, NULL) ORDER BY aa.create_time) AS 'nowTemperatureString', GROUP_CONCAT(IF(aa.out_temperature > 0, aa.valve_status, NULL) ORDER BY aa.create_time) AS 'nowValveStatusString', GROUP_CONCAT(IF(aa.out_temperature > 0, DATE_FORMAT(aa.create_time, '%Y-%m-%d'), NULL) ORDER BY aa.create_time) AS 'nowTimeString', aa.* FROM ( SELECT h.meter_num, h.out_temperature, h.create_time, h.read_time, h.valve_status, hhh.meter_num AS 'meterNumA', hhh.room_num AS 'roomNum' FROM pr_heat_reading h INNER JOIN ( SELECT b.meter_num, d.room_num, hh.open_time, hh.close_time FROM pr_heat_valve_archive b INNER JOIN pr_house d ON b.house_id = d.id AND b.company_id = #{companyId} AND b.org_id = d.org_id INNER JOIN pr_heat_station_partition f ON f.id = d.station_type
AND f.id = #{stationPartitionId}
INNER JOIN pr_heat_station g ON g.id = f.station_id
AND g.id = #{stationId}
INNER JOIN pr_options_heat hh ON hh.company_id = b.company_id AND hh.org_id IS NULL WHERE d.pay_status = 1 AND b.out_temperature > 0 AND b.valve_time > hh.open_time AND d.is_special = '0' LIMIT 50 ) hhh ON h.meter_num = hhh.meter_num WHERE h.out_temperature > 0 AND DATE_FORMAT(h.create_time, '%Y-%m-%d') BETWEEN DATE_FORMAT(hhh.open_time, '%Y-%m-%d') AND DATE_FORMAT(hhh.close_time, '%Y-%m-%d') GROUP BY h.meter_num, DATE_FORMAT(h.create_time, '%Y-%m-%d') ORDER BY h.create_time DESC ) aa GROUP BY aa.meterNumA LIMIT 50

SELECT GROUP_CONCAT(h.out_temperature ORDER BY h.read_time) AS 'nowTemperatureString', GROUP_CONCAT(h.valve_status ORDER BY h.read_time) AS 'nowValveStatusString', h.id, h.room_num AS 'roomNum', h.meter_num AS 'meterNum', h.type, h.setting_status AS 'settingStatus', h.valve_status AS 'valveStatus', h.read_time AS 'readTime', h.in_temperature AS 'inTemperature', h.out_temperature AS 'outTemperature', h.now_temperature AS 'nowTemperature', h.create_by AS 'createBy', AVG(h.in_temperature) AS 'avgInTemperature', AVG(h.out_temperature) AS 'avgOutTemperature', AVG(h.now_temperature) AS 'avgNowTemperature', AVG(h.valve_status) AS 'avgValveStatus' FROM pr_heat_reading_copy1 h
AND h.room_num IN
#{item.label}
AND h.read_time BETWEEN #{startTime} AND #{endTime}
GROUP BY h.room_num ORDER BY h.read_time

SELECT c.org_name AS 'orgName', c.building_name AS 'buildingName', c.unit_code AS 'unitCode', c.room_num AS 'roomNum', c.floor, a.id, a.house_id AS 'houseId', a.meter_serial AS 'meterSerial', a.meter_num AS 'meterNum', a.meter_arc_code AS 'meterArcCode', b.in_temperature AS 'inTemperature', b.out_temperature AS 'outTemperature', b.attack_status AS 'attackStatus', b.setting_status AS 'settingStatus', b.valve_status AS 'valveStatus', b.create_time AS 'createTime', b.read_time AS 'readTime', f.phone, f.user_name AS 'userName', b.total_worktime AS 'totalWorktime', MAX(IFNULL(b.csq, 0)) AS 'csq', b.voltage, MAX(IFNULL(b.humi, 0)) AS 'humi', MAX(IFNULL(b.temperature, 0)) AS 'temperature', MAX(IFNULL(b.total_heat, a.total_heat)) AS 'totalHeat', MAX(IFNULL(b.total_flow, a.total_flow)) AS 'totalFlow', b.rb_status1 AS 'rbStatus1', b.rb_status2 AS 'rbStatus2' FROM pr_heat_archive a LEFT JOIN pr_heat_reading b ON a.meter_num = b.meter_num LEFT JOIN pr_house c ON a.house_id = c.id LEFT JOIN pr_building d ON c.building_id = d.id LEFT JOIN pr_user_house f ON a.house_id = f.house_id WHERE a.company_id = #{companyId} AND a.is_changed = '0'
AND a.org_id = #{orgId}
AND c.building_id = #{buildingId}
AND c.unit_code = #{unitCode}
AND a.meter_arc_code = #{meterArcCode}
AND (c.room_num LIKE CONCAT('%', TRIM(#{search}), '%') OR f.phone LIKE CONCAT('%', TRIM(#{search}), '%') OR a.meter_num LIKE CONCAT('%', TRIM(#{search}), '%'))
GROUP BY a.meter_num, b.read_time ORDER BY a.meter_num, b.read_time DESC
